const d = $input.first().json;

const nome_cliente = d.nome || d.name || d.cliente || 'Cliente';
const azienda = d.azienda || d.company || nome_cliente;
const tipo_servizio = d.servizio || d.service || d.tipo || 'consulenza';
const data_inizio = d.data_inizio || new Date().toLocaleDateString('it-IT');
const email_cliente = d.email || '';
const nome_cartella = azienda + ' — Onboarding ' + new Date().getFullYear();

const tasks = [
  '- [ ] Invio questionario iniziale',
  '- [ ] Kickoff call pianificato',
  '- [ ] Accesso condiviso tools e credenziali',
  '- [ ] Prima deliverable definita e approvata',
  '- [ ] Check-in settimana 1',
  '- [ ] Check-in settimana 2',
  '- [ ] Review e chiusura onboarding'
].join('\n');

const lines = [
  'Scrivi una email di benvenuto professionale e calorosa per un nuovo cliente.',
  '',
  'DATI CLIENTE:',
  '- Nome: ' + nome_cliente,
  '- Azienda: ' + azienda,
  '- Servizio acquistato: ' + tipo_servizio,
  '- Data inizio collaborazione: ' + data_inizio,
  '',
  'Rispondi SOLO con JSON valido (nessun markdown, nessun testo extra):',
  '{',
  '  "oggetto": "<oggetto email breve, max 60 caratteri>",',
  '  "corpo_html": "<email HTML completa: apertura calorosa con nome, conferma servizio, 3 prossimi passi numerati, chiusura con invito a rispondere per domande — tono professionale ma umano, max 200 parole>"',
  '}'
].join('\n');

return [{ json: {
  nome_cliente,
  email_cliente,
  azienda,
  tipo_servizio,
  data_inizio,
  nome_cartella,
  _taskade_body: {
    name: 'Onboarding — ' + azienda,
    content: tasks
  },
  _claude_body: {
    model: 'claude-sonnet-4-6',
    max_tokens: 1024,
    messages: [{ role: 'user', content: lines }]
  }
} }];

const d = $('Prepara Dati Cliente').first().json;
const text = $input.first().json.content[0].text.trim();

const m = text.match(/\{[\s\S]*\}/);
if (!m) throw new Error('Nessun JSON trovato: ' + text.slice(0, 200));

let parsed;
try { parsed = JSON.parse(m[0]); }
catch(e) { throw new Error('JSON non parsabile: ' + m[0].slice(0, 200)); }

return [{ json: {
  ...d,
  email_oggetto: parsed.oggetto,
  email_corpo_html: parsed.corpo_html
} }];
